相机控制：
- OrbitControls 不在 r128 核心包中，需要额外引入，或手写。
- 手写简单的：记录鼠标 isDown，计算 delta，映射到 cameraAngle theta/phi。
- 滚轮：调整 camera radius。

```javascript
const cameraState = { theta: 0, phi: Math.PI/2.5, radius: 12 };

// mouse events on container
container.addEventListener('mousedown', e => { mouse.isDown = true; mouse.lastX = e.clientX; mouse.lastY = e.clientY; });
window.addEventListener('mouseup', () => mouse.isDown = false);
window.addEventListener('mousemove', e => {
  if (!mouse.isDown) return;
  const dx = e.clientX - mouse.lastX;
  const dy = e.clientY - mouse.lastY;
  cameraState.theta -= dx * 0.01;
  cameraState.phi -= dy * 0.01;
  cameraState.phi = Math.max(0.1, Math.min(Math.PI - 0.1, cameraState.phi));
  mouse.lastX = e.clientX;
  mouse.lastY = e.clientY;
  updateCamera();
});

container.addEventListener('wheel', e => {
  cameraState.radius += e.deltaY * 0.01;
  cameraState.radius = Math.max(4, Math.min(20, cameraState.radius));
  updateCamera();
});

function updateCamera() {
  const r = cameraState.radius;
  camera.position.x = r * Math.sin(cameraState.phi) * Math.cos(cameraState.theta);
  camera.position.y = r * Math.cos(cameraState.phi);
  camera.position.z = r * Math.sin(cameraState.phi) * Math.sin(cameraState.theta);
  camera.lookAt(0,0,0);
}
```

